<?php
namespace App\Services\Billing;use App\Models\{AiUsageLog,FeatureUsageLog,Project,StorageUsageLog,Task,TaskAttachment,Workspace};use App\Services\Audit\AuditLogService;
class PlanLimitService{public function __construct(private AuditLogService $audit){}public function canAddUser(Workspace $w):bool{return $this->allowed($w,'user_limit',$w->users()->count()+1,'users');}public function canCreateProject(Workspace $w):bool{return $this->allowed($w,'project_limit',Project::where('workspace_id',$w->id)->count()+1,'projects');}public function canCreateTask(Workspace $w):bool{$limit=$this->getLimit($w,'task_monthly_limit');return $limit===null||$this->getUsage($w,'tasks')+1<=$limit;}public function canUseStorage(Workspace $w,int $bytes):bool{$limit=$this->getLimit($w,'storage_limit_mb');if($limit===null)return true;$used=(float)TaskAttachment::where('workspace_id',$w->id)->sum('file_size')/1048576;return ($used+($bytes/1048576))<=$limit;}public function canUseAi(Workspace $w):bool{$limit=$this->getLimit($w,'ai_monthly_quota');return $limit===null||$this->getUsage($w,'ai')+1<=$limit;}public function getLimit(Workspace $w,string $key):mixed{$plan=$w->subscription?->plan;if(!$plan)return null;return match($key){'user_limit'=>$plan->user_limit,'project_limit'=>$plan->project_limit,'storage_limit_mb'=>$plan->storage_limit_mb,'ai_monthly_quota'=>$plan->ai_monthly_quota,'task_monthly_limit'=>$plan->features()->where('feature_key','task_monthly_limit')->value('value'),default=>$plan->features()->where('feature_key',$key)->value('value')};}public function getUsage(Workspace $w,string $feature):mixed{return match($feature){'users'=>$w->users()->count(),'projects'=>Project::where('workspace_id',$w->id)->count(),'tasks'=>Task::where('workspace_id',$w->id)->whereMonth('created_at',now()->month)->whereYear('created_at',now()->year)->count(),'ai'=>class_exists(AiUsageLog::class)?AiUsageLog::where('workspace_id',$w->id)->whereMonth('created_at',now()->month)->whereYear('created_at',now()->year)->count():FeatureUsageLog::where('workspace_id',$w->id)->where('feature_key','ai')->whereMonth('usage_date',now()->month)->sum('usage_count'),'storage_mb'=>StorageUsageLog::where('workspace_id',$w->id)->latest('calculated_at')->value('used_mb')??0,default=>FeatureUsageLog::where('workspace_id',$w->id)->where('feature_key',$feature)->sum('usage_count')};}private function allowed(Workspace $w,string $limit,int|float $next,string $feature):bool{$l=$this->getLimit($w,$limit);$ok=$l===null||$next<=$l;if(!$ok)$this->audit->log('plan_limit_blocked',null,[],['feature'=>$feature,'limit'=>$l,'attempted'=>$next],$w->id);return $ok;}}
